#!/bin/bash
set -euo pipefail
export DEBIAN_FRONTEND=noninteractive
apt-get update -y
apt-get install -y nginx-full
# One-LB SNI host-router: L4 passthrough (no TLS termination), routes :443 by SNI.
# Preserves end-to-end TLS to each origin; matches the old per-service LB behaviour
# while consolidating them into a single ingress. pd-ONE-LB-CONSOLIDATION.
cat >/etc/nginx/nginx.conf <<'NGINX'
include /etc/nginx/modules-enabled/*.conf;
user www-data;
worker_processes auto;
events { worker_connections 2048; }
stream {
  map $ssl_preread_server_name $pyx_upstream {
    auth.pyxcloud.io            sso_prod;
    vpn-auth.pyxcloud.io        sso_staging;
    staging-api.pyxcloud.io     backend_staging;
    mcp.passo.build             mcp_staging;
    staging-mcp.passo.build     mcp_staging;
    api.pyxcloud.io             backend_prod;
    staging.passo.build         staging_fe;
    staging-console.passo.build staging_fe;
    default                     sink;
  }
  upstream sso_prod        { server 164.92.248.51:443; server 207.154.231.103:443; }
  upstream sso_staging     { server 206.189.53.146:443; }
  upstream backend_staging { server 104.248.245.240:443; }
  upstream backend_prod    { server 178.128.195.90:443; server 167.99.243.188:443; }
  upstream mcp_staging     { server 178.128.201.212:443; }
  # staging_fe: dedicated, stateless nginx-to-Amplify shim (pd-STAGING-FE-SHIM,
  # platform_bootstrap_staging_fe_do.go), replacing the fragile shim hand-managed
  # on the obs droplet (10.0.1.7). PLACEHOLDER IP below: this baseline topology
  # only takes effect for an edge droplet CREATED fresh from this user_data — the
  # LIVE edge routers (pyx-edge-1/2) are reconciled out-of-band, same as the
  # api_prod/mcp_staging routes before this one. Apply the real IP with
  # add-staging-fe-route.sh (gated, mirrors add-api-prod-route.sh) AFTER the
  # staging-fe droplet (tag pyx-staging-fe) is up and verified.
  upstream staging_fe      { server 10.0.1.20:443; } # PLACEHOLDER: doctl compute droplet list --tag-name pyx-staging-fe --format PrivateIPv4
  upstream sink            { server 127.0.0.1:9; }
  server {
    listen 443;
    ssl_preread on;
    proxy_pass $pyx_upstream;
    proxy_connect_timeout 5s;
  }
}
NGINX
nginx -t && systemctl enable nginx && systemctl restart nginx
